@asset(partitions_def=daily_partitions)
def validate_enterprise_data(context, raw_data):
    partition_key = context.partition_key
    validation_results = []

    for record in raw_data:
        validation_result = {
            'record_id': record.get('id'),
            'timestamp': partition_key,
            'is_valid': True,
            'errors': []
        }

        # Validate required fields
        required_fields = ['id', 'timestamp', 'source_system']
        for field in required_fields:
            if not record.get(field):
                validation_result['is_valid'] = False
                validation_result['errors'].append(f'Missing {field}')

        validation_results.append(validation_result)

    return validation_results

def capture_cdc_events(source_db, s3_bucket, partition_date):
    """Capture CDC events and write to S3 with idempotency."""
    events = source_db.get_change_log(partition_date)

    for event in events:
        key = f"raw/cdc/{partition_date}/{event.table}/{event.id}.json"

        # Idempotent write - check if exists
        if not s3_client.object_exists(key):
            s3_client.put_object(
                key=key,
                body=json.dumps(event.to_dict()),
                metadata={'table': event.table, 'operation': event.op}
            )

    return len(events)

